with active_users as (select id, username, email from users where status = 'ACTIVE' and deleted_at is null), user_orders as (select user_id, count(*) as order_count, sum(total_amount) as total_spent from orders where created_at >= '2023-01-01' group by user_id) select u.username, u.email, o.order_count, o.total_spent from active_users u left join user_orders o on u.id = o.user_id order by o.total_spent desc limit 100 ;